import{_ as e,a as t,b as n,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as i,o as s,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Tambah Yandex Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/yandex.md","filePath":"ms-MY/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"ms-MY/upload/yandex.md"};function p(c,a,h,u,k,m){return s(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="tambah-yandex-channel" tabindex="-1">Tambah Yandex Channel <a class="header-anchor" href="#tambah-yandex-channel" aria-label="Permalink to &quot;Tambah Yandex Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan-dahulu" tabindex="-1">Perkara Yang Perlu Disediakan Dahulu <a class="header-anchor" href="#perkara-yang-perlu-disediakan-dahulu" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan Dahulu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Diperlukan</th></tr></thead><tbody><tr><td>Yandex account</td><td>Digunakan untuk sign in dan authorize Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>Digunakan untuk generate <code>Client ID</code> dan <code>Client Secret</code></td></tr><tr><td>ImgBed domain anda</td><td>Digunakan untuk OAuth redirect URI</td></tr><tr><td>Available Yandex Disk storage</td><td>Digunakan sebagai lokasi file storage sebenar</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-cipta-yandex-oauth-app" tabindex="-1">Step 1: Cipta Yandex OAuth App <a class="header-anchor" href="#step-1-cipta-yandex-oauth-app" aria-label="Permalink to &quot;Step 1: Cipta Yandex OAuth App&quot;">​</a></h3><ol><li>Buka halaman penciptaan Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Jika anda redirected ke sign in, sign in dengan Yandex account dahulu.</li><li>Cipta app baharu.</li><li>Beri nama app yang mudah dikenali, contohnya <code>imgbed-yandex</code>.</li><li>Cari callback atau redirect URL settings.</li><li>Masukkan:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-sahkan-permissions" tabindex="-1">Step 2: Sahkan Permissions <a class="header-anchor" href="#step-2-sahkan-permissions" aria-label="Permalink to &quot;Step 2: Sahkan Permissions&quot;">​</a></h3><p>Untuk ImgBed Yandex integration semasa, kekalkan empat permissions ini di bawah <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Membolehkan ImgBed menyimpan files dalam app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Membaca files dan download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Upload files, cipta folders dan delete files</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Membaca disk quota dan used space</td></tr></tbody></table><p>Jika anda juga melihat permissions ini di bawah <code>Yandex ID API</code>, ia optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Core upload, download, deletion dan quota features bergantung terutamanya pada empat permissions <code>Yandex.Disk REST API</code> di atas.</p><p><img src="'+e+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-copy-app-credentials" tabindex="-1">Step 3: Copy App Credentials <a class="header-anchor" href="#step-3-copy-app-credentials" aria-label="Permalink to &quot;Step 3: Copy App Credentials&quot;">​</a></h3><p>Selepas app dicipta, copy:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-isi-yandex-channel" tabindex="-1">Step 4: Isi Yandex Channel <a class="header-anchor" href="#step-4-isi-yandex-channel" aria-label="Permalink to &quot;Step 4: Isi Yandex Channel&quot;">​</a></h3><p>Dalam Upload Settings, pilih <code>Yandex</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Apa Yang Perlu Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali, contohnya <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>Biarkan kosong buat masa ini</td></tr><tr><td>Root directory</td><td>Optional. Default ialah <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-dapatkan-refresh-token" tabindex="-1">Step 5: Dapatkan Refresh Token <a class="header-anchor" href="#step-5-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 5: Dapatkan Refresh Token&quot;">​</a></h3><ol><li>Dalam ImgBed, klik <code>Get Token</code>.</li><li>Sign in ke Yandex account yang mahu disambungkan.</li><li>Approve authorization prompt.</li><li>Callback page akan menunjukkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste dalam field <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h3><p>Selepas semua field diisi, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Cipta app</span></span>
<span class="line"><span>-&gt; Tambah https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Sahkan Yandex Disk permissions</span></span>
<span class="line"><span>-&gt; Copy Client ID dan Client Secret</span></span>
<span class="line"><span>-&gt; Isi Client ID / Client Secret dalam ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=i(r,[["render",p]]);export{x as __pageData,y as default};
